class Solution:
    def countDays(self, days, meetings):
        meetings.sort()
        free = 0
        cur_start, cur_end = meetings[0]
        for s, e in meetings[1:]:
            if s > cur_end + 1:
                free += cur_end - cur_start + 1
                cur_start, cur_end = s, e
            else:
                cur_end = max(cur_end, e)
        free += cur_end - cur_start + 1
        return days - free

