var countDays = function(days, meetings) {
    meetings.sort((a, b) => a[0] - b[0]);
    let free = 0;
    let [curStart, curEnd] = meetings[0];
    for (let i = 1; i < meetings.length; i++) {
        const [s, e] = meetings[i];
        if (s > curEnd + 1) {
            free += curEnd - curStart + 1;
            curStart = s;
            curEnd = e;
        } else {
            curEnd = Math.max(curEnd, e);
        }
    }
    free += curEnd - curStart + 1;
    return days - free;
};
